export const styles = "\n@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@400;600;700&family=Syne:wght@700;800&family=DM+Sans:wght@400;500&display=swap');\n\n.artifact-scope {\n  --bg: #0c0c0e;\n  --surface: #111116;\n  --card: #18181d;\n  --border: #26262e;\n  --border2: #1e1e26;\n\n  --user:      #38bdf8;\n  --app:       #fb923c;\n  --api:       #a78bfa;\n  --sandbox:   #f472b6;\n  --tool:      #fbbf24;\n  --ctx:       #34d399;\n\n  --user-bg:    #071824;\n  --app-bg:     #1a0e06;\n  --api-bg:     #120e1e;\n  --sandbox-bg: #1a0812;\n  --tool-bg:    #181208;\n  --ctx-bg:     #071812;\n\n  --text: #e4e4ef;\n  --muted: #64647a;\n  --sub: #9898b0;\n}\n\n.artifact-scope, .artifact-scope * { box-sizing: border-box; margin: 0; padding: 0; }\n\n.artifact-scope {\n  background: var(--bg);\n  color: var(--text);\n  font-family: 'DM Sans', sans-serif;\n  font-size: 14px;\n  line-height: 1.5;\n  padding: 32px 16px 80px;\n}\n\n.page { max-width: 1140px; margin: 0 auto; }\n\n.topbar {\n  display: flex; align-items: center; justify-content: space-between;\n  padding-bottom: 20px; border-bottom: 1px solid var(--border); margin-bottom: 32px;\n}\n.brand { font-family: 'IBM Plex Mono', monospace; font-size: 11px; font-weight: 700; letter-spacing: 0.12em; text-transform: uppercase; color: #f472b6; }\n.meta  { font-family: 'IBM Plex Mono', monospace; font-size: 11px; color: var(--muted); text-align: right; line-height: 1.6; }\n\n.hero { margin-bottom: 32px; }\n.hero h1 { font-family: 'Syne', sans-serif; font-size: clamp(22px, 4vw, 36px); font-weight: 800; letter-spacing: -0.02em; margin-bottom: 8px; }\n.hero h1 em { font-style: normal; color: #f472b6; }\n.hero p { color: var(--sub); font-size: 14.5px; max-width: 680px; line-height: 1.7; }\n\n.tabs {\n  display: flex; gap: 4px; margin-bottom: 32px;\n  border-bottom: 1px solid var(--border); padding-bottom: 0;\n}\n.tab {\n  font-family: 'IBM Plex Mono', monospace; font-size: 11.5px; font-weight: 700;\n  letter-spacing: 0.08em; text-transform: uppercase;\n  padding: 10px 20px; border-radius: 6px 6px 0 0;\n  border: 1px solid transparent; border-bottom: none;\n  cursor: pointer; color: var(--muted);\n  background: transparent; transition: all .2s;\n  position: relative; bottom: -1px;\n}\n.tab:hover { color: var(--text); background: var(--surface); }\n.tab.active { color: var(--text); background: var(--card); border-color: var(--border); border-bottom-color: var(--card); }\n\n.panel { display: none; }\n.panel.active { display: block; }\n\n.legend { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 24px; }\n.leg-item { display: flex; align-items: center; gap: 7px; background: var(--card); border: 1px solid var(--border); border-radius: 20px; padding: 5px 12px; }\n.leg-dot { width: 10px; height: 10px; border-radius: 50%; flex-shrink: 0; }\n.leg-label { font-family: 'IBM Plex Mono', monospace; font-size: 11px; font-weight: 600; color: var(--sub); }\n\n.callout { border-radius: 8px; padding: 12px 16px; margin: 0 0 20px; display: flex; gap: 10px; font-size: 13px; line-height: 1.65; }\n.callout.tip  { background: #071812; border: 1px solid #1a3820; color: #86efac; }\n.callout.info { background: #07121a; border: 1px solid #1a2e40; color: #93c5fd; }\n.callout.pink { background: #1a0814; border: 1px solid #3a1030; color: #f9a8d4; }\n.callout strong { color: var(--text); }\n\n/* ── SEQUENCE CANVAS ── */\n.seq-wrap { overflow-x: auto; padding-bottom: 16px; }\n\n.seq-canvas {\n  position: relative;\n  min-width: 860px;\n}\n\n/* Columns: User | App | Claude API | Sandbox | Your Tools */\n.COLS { --n: 5; }\n\n.actor-row {\n  display: grid;\n  grid-template-columns: repeat(5, 1fr);\n  margin-bottom: 0;\n  position: sticky; top: 0; z-index: 10;\n  background: var(--bg);\n  padding-bottom: 8px;\n  border-bottom: 1px solid var(--border2);\n}\n\n.actor-cell {\n  text-align: center;\n  padding: 10px 4px;\n}\n\n.actor-pill {\n  font-family: 'IBM Plex Mono', monospace;\n  font-size: 11px; font-weight: 700;\n  letter-spacing: 0.07em; text-transform: uppercase;\n  padding: 6px 10px; border-radius: 5px;\n  display: inline-block; border: 1px solid;\n}\n\n/* lifeline grid */\n.lifeline-grid {\n  display: grid;\n  grid-template-columns: repeat(5, 1fr);\n  position: absolute;\n  left: 0; right: 0;\n  pointer-events: none;\n}\n\n.ll { border-left: 1px dashed; margin-left: 50%; }\n\n/* message row */\n.msg-row {\n  display: grid;\n  grid-template-columns: repeat(5, 1fr);\n  min-height: 46px;\n  position: relative;\n  cursor: pointer;\n  border-radius: 4px;\n  transition: background .15s;\n  align-items: center;\n}\n.msg-row:hover { background: rgba(255,255,255,.027); }\n\n/* activation band */\n.act-band {\n  position: absolute;\n  width: 9px;\n  background: rgba(255,255,255,.06);\n  border: 1px solid rgba(255,255,255,.12);\n  border-radius: 2px;\n}\n\n/* arrow */\n.arrow {\n  position: absolute;\n  top: 50%;\n  transform: translateY(-50%);\n  height: 0;\n  pointer-events: none;\n}\n\n.arrow.solid  { border-top: 1.5px solid; }\n.arrow.dashed { border-top: 1.5px dashed; }\n\n/* arrowhead right */\n.arrow::after {\n  content: '';\n  position: absolute;\n  top: 50%; transform: translateY(-50%);\n  width: 0; height: 0;\n  border-top: 5px solid transparent;\n  border-bottom: 5px solid transparent;\n}\n.arrow.right::after { right: -2px; border-left: 8px solid; }\n.arrow.left::after  { left: -2px;  border-right: 8px solid; }\n\n/* label on arrow */\n.arrow-lbl {\n  position: absolute;\n  font-family: 'IBM Plex Mono', monospace;\n  font-size: 10.5px;\n  padding: 1px 5px;\n  background: var(--bg);\n  border-radius: 3px;\n  white-space: nowrap;\n  top: 50%;\n  transform: translateY(-160%);\n  pointer-events: none;\n}\n\n/* note */\n.note { margin: 2px 16px 6px; background: #131320; border: 1px solid #24244a; border-radius: 6px; padding: 8px 12px; font-size: 12px; color: #9898d8; line-height: 1.55; }\n.note strong { color: #b0b0f8; }\n\n/* group header */\n.group-hdr {\n  display: flex; align-items: center; gap: 10px;\n  padding: 8px 14px; margin: 10px 0 4px;\n  border-radius: 6px;\n  cursor: pointer; user-select: none;\n  border: 1px solid;\n}\n.group-hdr .g-badge {\n  font-family: 'IBM Plex Mono', monospace; font-size: 10px; font-weight: 700;\n  padding: 2px 8px; border-radius: 3px;\n}\n.group-hdr .g-title { font-family: 'Syne', sans-serif; font-weight: 700; font-size: 13.5px; }\n.group-hdr .g-chevron { margin-left: auto; font-size: 13px; transition: transform .2s; }\n.group-hdr.closed .g-chevron { transform: rotate(-90deg); }\n.group-body.hidden { display: none; }\n\n/* ── DRILL-DOWN CARDS ── */\n.dd-card {\n  background: var(--card); border: 1px solid var(--border);\n  border-radius: 10px; overflow: hidden; margin-bottom: 12px;\n}\n.dd-head {\n  display: flex; align-items: center; gap: 10px;\n  padding: 11px 16px; background: var(--surface); border-bottom: 1px solid var(--border);\n}\n.dd-step-badge {\n  font-family: 'IBM Plex Mono', monospace; font-size: 10px; font-weight: 700;\n  padding: 2px 9px; border-radius: 4px; flex-shrink: 0;\n  border: 1px solid;\n}\n.dd-title { font-family: 'Syne', sans-serif; font-weight: 700; font-size: 14px; }\n.dd-from  { margin-left: auto; font-family: 'IBM Plex Mono', monospace; font-size: 10px; color: var(--muted); white-space: nowrap; }\n.dd-body  { padding: 16px; }\n.dd-cols-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }\n.dd-cols-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; }\n.dd-label { font-family: 'IBM Plex Mono', monospace; font-size: 10px; color: var(--muted); letter-spacing: .1em; text-transform: uppercase; margin-bottom: 8px; }\n.dd-pre {\n  font-family: 'IBM Plex Mono', monospace; font-size: 11px; line-height: 1.75;\n  color: #c4c4d4; background: #0d0d14; border: 1px solid var(--border2);\n  border-radius: 6px; padding: 12px; overflow-x: auto; white-space: pre;\n}\n.dd-token {\n  background: #071812; border: 1px solid #1a3820;\n  border-radius: 6px; padding: 13px 14px;\n  font-family: 'IBM Plex Mono', monospace; font-size: 11px;\n  color: #39d98a; line-height: 1.9;\n}\n.dd-key  { color: #67e8f9; }\n.dd-str  { color: #86efac; }\n.dd-val  { color: #fbbf24; }\n.dd-cmt  { color: #44445a; font-style: italic; }\n.dd-pink { color: #f9a8d4; }\n.dd-pur  { color: #c4b5fd; }\n\n/* detail popup */\n.popup {\n  position: fixed; bottom: 24px; right: 24px;\n  width: 380px; max-height: 72vh; overflow-y: auto;\n  background: var(--card); border: 1px solid var(--border);\n  border-radius: 12px; padding: 20px;\n  box-shadow: 0 20px 60px rgba(0,0,0,.65);\n  z-index: 200; display: none;\n  animation: sup .2s ease;\n}\n@keyframes sup { from { opacity:0; transform:translateY(14px); } to { opacity:1; transform:translateY(0); } }\n.popup.on { display: block; }\n.popup-close { position: absolute; top: 12px; right: 14px; background: none; border: none; color: var(--muted); font-size: 18px; cursor: pointer; }\n.popup-close:hover { color: var(--text); }\n.popup-step { font-family: 'IBM Plex Mono', monospace; font-size: 10px; color: var(--muted); letter-spacing: .1em; text-transform: uppercase; margin-bottom: 4px; }\n.popup-title { font-family: 'Syne', sans-serif; font-size: 17px; font-weight: 700; margin-bottom: 10px; line-height: 1.2; }\n.popup-chips { display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 12px; }\n.popup-chip { font-family: 'IBM Plex Mono', monospace; font-size: 10px; padding: 3px 9px; border-radius: 20px; border: 1px solid; }\n.popup-desc { font-size: 13px; color: var(--sub); line-height: 1.7; margin-bottom: 12px; }\n.popup-pre { font-family: 'IBM Plex Mono', monospace; font-size: 11px; line-height: 1.7; color: #c4c4d4; background: #0d0d14; border: 1px solid var(--border2); border-radius: 6px; padding: 12px; overflow-x: auto; white-space: pre; }\n.popup-token { margin-top: 10px; background: #071812; border: 1px solid #1a3820; border-radius: 6px; padding: 10px 12px; font-family: 'IBM Plex Mono', monospace; font-size: 11px; color: #39d98a; }\n\n@media (max-width: 600px) { .dd-cols-2, .dd-cols-3 { grid-template-columns: 1fr; } }\n";

export const html = "<div class=\"page\">\n\n<div class=\"topbar\">\n  <a href=\"/\" class=\"brand\" style=\"text-decoration:none;cursor:pointer;\">◀ harrytruong</a>\n  <div class=\"meta\">Advanced Tool Use 2.0<br/>Programmatic Tool Calling</div>\n</div>\n\n<div class=\"hero\">\n  <h1>Programmatic Tool Calling —<br/><em>Sequence Diagram</em></h1>\n  <p>Concrete example: \"Which team members exceeded their Q3 travel budget?\" — 3 tools, 20 people, 2000+ expense records. Classic calling: 21 API round-trips, 50KB+ in context. Programmatic calling: 1 script, only the final summary enters Claude's context.</p>\n</div>\n\n<div class=\"tabs\">\n  <button class=\"tab active\" onclick=\"switchTab('overview', this)\">① Overview</button>\n  <button class=\"tab\" onclick=\"switchTab('drilldown', this)\">② Drill-Down</button>\n</div>\n\n<!-- ══════════════════════════════════════════\n     OVERVIEW\n══════════════════════════════════════════ -->\n<div class=\"panel active\" id=\"panel-overview\">\n\n  <div class=\"legend\">\n    <div class=\"leg-item\"><div class=\"leg-dot\" style=\"background:var(--user)\"></div><div class=\"leg-label\">User</div></div>\n    <div class=\"leg-item\"><div class=\"leg-dot\" style=\"background:var(--app)\"></div><div class=\"leg-label\">Your App</div></div>\n    <div class=\"leg-item\"><div class=\"leg-dot\" style=\"background:var(--api)\"></div><div class=\"leg-label\">Claude API</div></div>\n    <div class=\"leg-item\"><div class=\"leg-dot\" style=\"background:var(--sandbox)\"></div><div class=\"leg-label\">Code Sandbox</div></div>\n    <div class=\"leg-item\"><div class=\"leg-dot\" style=\"background:var(--tool)\"></div><div class=\"leg-label\">Your Tools</div></div>\n  </div>\n\n  <div class=\"callout info\">\n    <span>💡</span>\n    <div><strong>Click any message</strong> to see the exact JSON, what flows between actors, and the context impact at that step.</div>\n  </div>\n\n  <div class=\"seq-wrap\">\n  <div class=\"seq-canvas\" style=\"padding-top: 68px; padding-bottom: 24px;\">\n\n    <!-- Actor Row -->\n    <div class=\"actor-row\">\n      <div class=\"actor-cell\"><span class=\"actor-pill\" style=\"background:var(--user-bg);color:var(--user);border-color:var(--user)\">User</span></div>\n      <div class=\"actor-cell\"><span class=\"actor-pill\" style=\"background:var(--app-bg);color:var(--app);border-color:var(--app)\">Your App</span></div>\n      <div class=\"actor-cell\"><span class=\"actor-pill\" style=\"background:var(--api-bg);color:var(--api);border-color:var(--api)\">Claude API</span></div>\n      <div class=\"actor-cell\"><span class=\"actor-pill\" style=\"background:var(--sandbox-bg);color:var(--sandbox);border-color:var(--sandbox)\">Code Sandbox</span></div>\n      <div class=\"actor-cell\"><span class=\"actor-pill\" style=\"background:var(--tool-bg);color:var(--tool);border-color:var(--tool)\">Your Tools</span></div>\n    </div>\n\n    <!-- Lifelines (overlay) -->\n    <div class=\"lifeline-grid\" style=\"top:68px;bottom:0;\">\n      <div class=\"ll\" style=\"border-color:var(--user);opacity:.2;\"></div>\n      <div class=\"ll\" style=\"border-color:var(--app);opacity:.2;\"></div>\n      <div class=\"ll\" style=\"border-color:var(--api);opacity:.2;\"></div>\n      <div class=\"ll\" style=\"border-color:var(--sandbox);opacity:.2;\"></div>\n      <div class=\"ll\" style=\"border-color:var(--tool);opacity:.2;\"></div>\n    </div>\n\n    <!-- ── GROUP A ── -->\n    <div class=\"group-hdr\" style=\"background:rgba(251,146,60,.05);border-color:#3a2010;color:var(--app)\" onclick=\"toggleGrp(this)\">\n      <span class=\"g-badge\" style=\"background:var(--app-bg);color:var(--app);\">A</span>\n      <span class=\"g-title\">Setup — Register tools + enable code_execution</span>\n      <span class=\"g-chevron\">▾</span>\n    </div>\n    <div class=\"group-body\">\n\n      <div class=\"msg-row\" onclick=\"showPopup('a1')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow right solid\" style=\"left:calc(10% + 0px);right:calc(40% + 0px);border-color:var(--app);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--app);left:6px;\">Register code_execution + 3 tools (allowed_callers)</span>\n        </div>\n      </div>\n\n      <div class=\"note\"><strong>Key config:</strong> Each tool declares <code>allowed_callers: [\"code_execution\"]</code> — authorizes the sandbox to invoke it programmatically without a human-in-the-loop round-trip.</div>\n    </div>\n\n    <!-- ── GROUP B ── -->\n    <div class=\"group-hdr\" style=\"background:rgba(56,189,248,.05);border-color:#1a3050;color:var(--user)\" onclick=\"toggleGrp(this)\">\n      <span class=\"g-badge\" style=\"background:var(--user-bg);color:var(--user);\">B</span>\n      <span class=\"g-title\">Turn 1 — User Request + Claude writes orchestration script</span>\n      <span class=\"g-chevron\">▾</span>\n    </div>\n    <div class=\"group-body\">\n\n      <div class=\"msg-row\" onclick=\"showPopup('b1')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow right solid\" style=\"left:calc(10% + 0px);right:calc(60% + 0px);border-color:var(--user);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--user);left:6px;\">\"Who exceeded Q3 travel budget?\"</span>\n        </div>\n      </div>\n\n      <div class=\"msg-row\" onclick=\"showPopup('b2')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow right solid\" style=\"left:calc(30% + 0px);right:calc(40% + 0px);border-color:var(--app);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--app);left:6px;\">POST /v1/messages (messages + tools[])</span>\n        </div>\n      </div>\n\n      <div class=\"msg-row\" onclick=\"showPopup('b3')\" style=\"min-height:54px;\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow left solid\" style=\"left:calc(30% + 0px);right:calc(40% + 0px);border-color:var(--api);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--api);right:6px;\">stop_reason:\"tool_use\" → server_tool_use: code_execution (Python script)</span>\n        </div>\n      </div>\n\n      <div class=\"note\"><strong>What Claude writes:</strong> A Python script using <code>async/await</code> to call <code>get_team_members()</code>, then parallel <code>get_expenses()</code> for all 20 people, then compare against budget. The script runs in the sandbox — Claude does NOT see the intermediate data.</div>\n    </div>\n\n    <!-- ── GROUP C ── -->\n    <div class=\"group-hdr\" style=\"background:rgba(244,114,182,.05);border-color:#3a1030;color:var(--sandbox)\" onclick=\"toggleGrp(this)\">\n      <span class=\"g-badge\" style=\"background:var(--sandbox-bg);color:var(--sandbox);\">C</span>\n      <span class=\"g-title\">Script Execution — Sandbox runs, pauses on each tool call</span>\n      <span class=\"g-chevron\">▾</span>\n    </div>\n    <div class=\"group-body\">\n\n      <!-- sandbox spawned -->\n      <div class=\"msg-row\" onclick=\"showPopup('c1')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow right solid\" style=\"left:calc(50% + 0px);right:calc(20% + 0px);border-color:var(--api);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--api);left:6px;\">Spawn sandbox container (container_id + expires_at)</span>\n        </div>\n      </div>\n\n      <!-- sandbox → tools: get_team_members (via caller) -->\n      <div class=\"msg-row\" onclick=\"showPopup('c2')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow right solid\" style=\"left:calc(70% + 0px);right:calc(0% + 6px);border-color:var(--sandbox);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--sandbox);left:6px;\">tool_use (caller:code_execution) → get_team_members(\"engineering\")</span>\n        </div>\n      </div>\n\n      <!-- tool → app result -->\n      <div class=\"msg-row\" onclick=\"showPopup('c3')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow left solid\" style=\"left:calc(30% + 0px);right:calc(0% + 6px);border-color:var(--tool);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--tool);right:6px;\">App receives tool_use → executes get_team_members → returns tool_result</span>\n        </div>\n      </div>\n\n      <!-- sandbox parallel: get_expenses ×20 -->\n      <div class=\"msg-row\" onclick=\"showPopup('c4')\" style=\"min-height:54px;\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow right dashed\" style=\"left:calc(70% + 0px);right:calc(0% + 6px);border-color:var(--sandbox);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--sandbox);left:6px;\">asyncio.gather() → get_expenses(id, \"Q3\") × 20 in parallel</span>\n        </div>\n      </div>\n\n      <!-- app returns 20 results -->\n      <div class=\"msg-row\" onclick=\"showPopup('c5')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow left dashed\" style=\"left:calc(30% + 0px);right:calc(0% + 6px);border-color:var(--tool);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--tool);right:6px;\">20 × tool_result (2000+ expense records processed inside script)</span>\n        </div>\n      </div>\n\n      <!-- sandbox: get_budget -->\n      <div class=\"msg-row\" onclick=\"showPopup('c6')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow right solid\" style=\"left:calc(70% + 0px);right:calc(0% + 6px);border-color:var(--sandbox);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--sandbox);left:6px;\">get_budget_by_level(levels)</span>\n        </div>\n      </div>\n\n      <div class=\"msg-row\" onclick=\"showPopup('c7')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow left solid\" style=\"left:calc(30% + 0px);right:calc(0% + 6px);border-color:var(--tool);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--tool);right:6px;\">budget limits returned → script computes overages</span>\n        </div>\n      </div>\n\n      <div class=\"note\">\n        <strong>Critical insight:</strong> All 2000+ expense records are <em>consumed and filtered inside the script</em>. They never enter Claude's context. The sandbox holds the data; Claude is never woken up between tool calls.\n      </div>\n    </div>\n\n    <!-- ── GROUP D ── -->\n    <div class=\"group-hdr\" style=\"background:rgba(52,211,153,.05);border-color:#1a3820;color:var(--ctx)\" onclick=\"toggleGrp(this)\">\n      <span class=\"g-badge\" style=\"background:var(--ctx-bg);color:var(--ctx);\">D</span>\n      <span class=\"g-title\">Script Completes — Only final output enters context</span>\n      <span class=\"g-chevron\">▾</span>\n    </div>\n    <div class=\"group-body\">\n\n      <div class=\"msg-row\" onclick=\"showPopup('d1')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow left solid\" style=\"left:calc(50% + 0px);right:calc(20% + 0px);border-color:var(--sandbox);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--sandbox);right:6px;\">script stdout → server_tool_result (code_execution)</span>\n        </div>\n      </div>\n\n      <div class=\"note\">\n        <strong>Context impact:</strong> Claude sees only: <code>\"5 people over budget: [Alice +$320, Bob +$150, ...]\"</code>\n        — ~60 tokens. Not the 2000+ raw expense lines it would have received classically.\n      </div>\n    </div>\n\n    <!-- ── GROUP E ── -->\n    <div class=\"group-hdr\" style=\"background:rgba(56,189,248,.05);border-color:#1a3050;color:var(--user)\" onclick=\"toggleGrp(this)\">\n      <span class=\"g-badge\" style=\"background:var(--user-bg);color:var(--user);\">E</span>\n      <span class=\"g-title\">Turn 2 — Final Answer</span>\n      <span class=\"g-chevron\">▾</span>\n    </div>\n    <div class=\"group-body\">\n\n      <div class=\"msg-row\" onclick=\"showPopup('e1')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow left solid\" style=\"left:calc(30% + 0px);right:calc(40% + 0px);border-color:var(--api);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--api);right:6px;\">stop_reason:\"end_turn\" → formatted answer</span>\n        </div>\n      </div>\n\n      <div class=\"msg-row\" onclick=\"showPopup('e2')\">\n        <div></div><div></div><div></div><div></div><div></div>\n        <div class=\"arrow left solid\" style=\"left:calc(10% + 0px);right:calc(60% + 0px);border-color:var(--user);\">\n          <span class=\"arrow-lbl\" style=\"color:var(--user);right:6px;\">\"5 team members exceeded budget: Alice ($320 over)…\"</span>\n        </div>\n      </div>\n\n      <div class=\"note\">\n        <strong>Total:</strong> 2 POST /v1/messages calls. Context: ~2,800 tokens total.\n        Classic approach would have needed ~22 round-trips and 50KB+ in context.\n      </div>\n    </div>\n\n  </div><!-- /seq-canvas -->\n  </div><!-- /seq-wrap -->\n\n</div><!-- /overview panel -->\n\n\n<!-- ══════════════════════════════════════════\n     DRILL-DOWN\n══════════════════════════════════════════ -->\n<div class=\"panel\" id=\"panel-drilldown\">\n\n  <div class=\"legend\">\n    <div class=\"leg-item\"><div class=\"leg-dot\" style=\"background:var(--user)\"></div><div class=\"leg-label\">User</div></div>\n    <div class=\"leg-item\"><div class=\"leg-dot\" style=\"background:var(--app)\"></div><div class=\"leg-label\">Your App</div></div>\n    <div class=\"leg-item\"><div class=\"leg-dot\" style=\"background:var(--api)\"></div><div class=\"leg-label\">Claude API</div></div>\n    <div class=\"leg-item\"><div class=\"leg-dot\" style=\"background:var(--sandbox)\"></div><div class=\"leg-label\">Code Sandbox</div></div>\n    <div class=\"leg-item\"><div class=\"leg-dot\" style=\"background:var(--tool)\"></div><div class=\"leg-label\">Your Tools</div></div>\n  </div>\n\n  <div class=\"callout pink\">\n    <span>🔬</span>\n    <div><strong>Drill-down:</strong> Exact JSON for every message, the <code>caller</code> field anatomy, container lifecycle, and per-step context token accounting.</div>\n  </div>\n\n  <!-- Step 1 -->\n  <div class=\"dd-card\">\n    <div class=\"dd-head\">\n      <div class=\"dd-step-badge\" style=\"color:var(--app);border-color:var(--app);background:var(--app-bg)\">Step 1</div>\n      <div class=\"dd-title\">App → API: Register code_execution + tools with allowed_callers</div>\n      <div class=\"dd-from\">App → Claude API</div>\n    </div>\n    <div class=\"dd-body dd-cols-2\">\n      <div>\n        <div class=\"dd-label\">What App Sends</div>\n        <div class=\"dd-pre\"><span class=\"dd-key\">\"tools\"</span>: [\n  <span class=\"dd-cmt\">// ① Anthropic server tool — code execution</span>\n  {\n    <span class=\"dd-key\">\"type\"</span>: <span class=\"dd-str\">\"code_execution_20260120\"</span>,\n    <span class=\"dd-key\">\"name\"</span>: <span class=\"dd-str\">\"code_execution\"</span>\n  },\n\n  <span class=\"dd-cmt\">// ② Your tools — authorize sandbox to call them</span>\n  {\n    <span class=\"dd-key\">\"name\"</span>: <span class=\"dd-str\">\"get_team_members\"</span>,\n    <span class=\"dd-key\">\"description\"</span>: <span class=\"dd-str\">\"Get team list by dept\"</span>,\n    <span class=\"dd-key\">\"input_schema\"</span>: { ... },\n    <span class=\"dd-val\">\"allowed_callers\"</span>: [<span class=\"dd-str\">\"code_execution\"</span>]\n  },\n  {\n    <span class=\"dd-key\">\"name\"</span>: <span class=\"dd-str\">\"get_expenses\"</span>,\n    <span class=\"dd-key\">\"description\"</span>: <span class=\"dd-str\">\"Get expense lines for user\"</span>,\n    <span class=\"dd-key\">\"input_schema\"</span>: { ... },\n    <span class=\"dd-val\">\"allowed_callers\"</span>: [<span class=\"dd-str\">\"code_execution\"</span>]\n  },\n  {\n    <span class=\"dd-key\">\"name\"</span>: <span class=\"dd-str\">\"get_budget_by_level\"</span>,\n    <span class=\"dd-val\">\"allowed_callers\"</span>: [<span class=\"dd-str\">\"code_execution\"</span>]\n  }\n]</div>\n      </div>\n      <div>\n        <div class=\"dd-label\">Why allowed_callers matters</div>\n        <div class=\"dd-pre\"><span class=\"dd-cmt\">// WITHOUT allowed_callers:</span>\n<span class=\"dd-cmt\">// Each tool_use from sandbox hits your app</span>\n<span class=\"dd-cmt\">// → your app must route it back</span>\n<span class=\"dd-cmt\">// → still requires manual round-trips</span>\n\n<span class=\"dd-cmt\">// WITH allowed_callers: [\"code_execution\"]:</span>\n<span class=\"dd-cmt\">// The sandbox is authorized to trigger</span>\n<span class=\"dd-cmt\">// tool calls directly in the flow</span>\n<span class=\"dd-cmt\">// Your app receives them grouped via</span>\n<span class=\"dd-cmt\">// the normal tool_use + tool_result loop</span>\n<span class=\"dd-cmt\">// but Claude is NOT woken between each</span></div>\n        <div style=\"margin-top:10px;\">\n          <div class=\"dd-label\">Token Impact</div>\n          <div class=\"dd-token\">code_execution tool: ~50 tokens<br/>3 tool defs loaded:  ~800 tokens<br/>─────────────────────────────<br/>Upfront total: <span class=\"dd-val\">~850 tokens</span></div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- Step 2 -->\n  <div class=\"dd-card\">\n    <div class=\"dd-head\">\n      <div class=\"dd-step-badge\" style=\"color:var(--api);border-color:var(--api);background:var(--api-bg)\">Step 2</div>\n      <div class=\"dd-title\">Claude writes the orchestration script — stop_reason: tool_use</div>\n      <div class=\"dd-from\">Claude API → App</div>\n    </div>\n    <div class=\"dd-body dd-cols-2\">\n      <div>\n        <div class=\"dd-label\">Claude's Response</div>\n        <div class=\"dd-pre\">{\n  <span class=\"dd-key\">\"stop_reason\"</span>: <span class=\"dd-str\">\"tool_use\"</span>,\n  <span class=\"dd-key\">\"content\"</span>: [\n    {\n      <span class=\"dd-key\">\"type\"</span>: <span class=\"dd-str\">\"text\"</span>,\n      <span class=\"dd-key\">\"text\"</span>: <span class=\"dd-str\">\"I'll query and analyze.\"</span>\n    },\n    {\n      <span class=\"dd-pur\">\"type\"</span>: <span class=\"dd-str\">\"server_tool_use\"</span>,\n      <span class=\"dd-key\">\"id\"</span>: <span class=\"dd-str\">\"srvtoolu_abc123\"</span>,\n      <span class=\"dd-key\">\"name\"</span>: <span class=\"dd-str\">\"code_execution\"</span>,\n      <span class=\"dd-key\">\"input\"</span>: {\n        <span class=\"dd-key\">\"code\"</span>: <span class=\"dd-str\">\"... python script ...\"</span>\n      }\n    }\n  ],\n  <span class=\"dd-pink\">\"container\"</span>: {\n    <span class=\"dd-key\">\"id\"</span>: <span class=\"dd-str\">\"container_xyz789\"</span>,\n    <span class=\"dd-key\">\"expires_at\"</span>: <span class=\"dd-str\">\"2026-03-05T14:30:00Z\"</span>\n  }\n}</div>\n      </div>\n      <div>\n        <div class=\"dd-label\">The Python Script Claude Writes</div>\n        <div class=\"dd-pre\"><span class=\"dd-cmt\"># This runs in the sandbox</span>\n<span class=\"dd-cmt\"># Claude writes this — you don't</span>\n\nteam = <span class=\"dd-val\">await</span> get_team_members(<span class=\"dd-str\">\"engineering\"</span>)\n\n<span class=\"dd-cmt\"># Parallel — NOT sequential</span>\ntasks = [\n  get_expenses(m[<span class=\"dd-str\">\"id\"</span>], <span class=\"dd-str\">\"Q3\"</span>)\n  <span class=\"dd-val\">for</span> m <span class=\"dd-val\">in</span> team\n]\nall_expenses = <span class=\"dd-val\">await</span> asyncio.gather(*tasks)\n\nbudgets = <span class=\"dd-val\">await</span> get_budget_by_level()\n\n<span class=\"dd-cmt\"># Filter IN SCRIPT — never enters context</span>\nover = []\n<span class=\"dd-val\">for</span> member, exp <span class=\"dd-val\">in</span> zip(team, all_expenses):\n  total = sum(e[<span class=\"dd-str\">\"amount\"</span>] <span class=\"dd-val\">for</span> e <span class=\"dd-val\">in</span> exp)\n  limit = budgets[member[<span class=\"dd-str\">\"level\"</span>]]\n  <span class=\"dd-val\">if</span> total > limit:\n    over.append({\n      <span class=\"dd-str\">\"name\"</span>: member[<span class=\"dd-str\">\"name\"</span>],\n      <span class=\"dd-str\">\"over\"</span>: total - limit\n    })\n\nprint(f<span class=\"dd-str\">\"Over budget: {over}\"</span>)\n<span class=\"dd-cmt\"># ↑ ONLY this print enters Claude's context</span></div>\n      </div>\n    </div>\n  </div>\n\n  <!-- Step 3 -->\n  <div class=\"dd-card\">\n    <div class=\"dd-head\">\n      <div class=\"dd-step-badge\" style=\"color:var(--sandbox);border-color:var(--sandbox);background:var(--sandbox-bg)\">Step 3</div>\n      <div class=\"dd-title\">Sandbox pauses → App receives tool_use with caller field</div>\n      <div class=\"dd-from\">Sandbox → App (via API)</div>\n    </div>\n    <div class=\"dd-body dd-cols-2\">\n      <div>\n        <div class=\"dd-label\">What App Receives (for get_team_members)</div>\n        <div class=\"dd-pre\">{\n  <span class=\"dd-key\">\"stop_reason\"</span>: <span class=\"dd-str\">\"tool_use\"</span>,\n  <span class=\"dd-key\">\"content\"</span>: [\n    <span class=\"dd-cmt\">// The sandbox's code_execution block</span>\n    {\n      <span class=\"dd-key\">\"type\"</span>: <span class=\"dd-str\">\"server_tool_use\"</span>,\n      <span class=\"dd-key\">\"id\"</span>: <span class=\"dd-str\">\"srvtoolu_abc123\"</span>,\n      <span class=\"dd-key\">\"name\"</span>: <span class=\"dd-str\">\"code_execution\"</span>,\n      <span class=\"dd-key\">\"input\"</span>: { <span class=\"dd-str\">\"code\"</span>: <span class=\"dd-str\">\"...\"</span> }\n    },\n    <span class=\"dd-cmt\">// The tool call FROM the script</span>\n    {\n      <span class=\"dd-key\">\"type\"</span>: <span class=\"dd-str\">\"tool_use\"</span>,\n      <span class=\"dd-key\">\"id\"</span>: <span class=\"dd-str\">\"toolu_team01\"</span>,\n      <span class=\"dd-key\">\"name\"</span>: <span class=\"dd-str\">\"get_team_members\"</span>,\n      <span class=\"dd-key\">\"input\"</span>: {<span class=\"dd-str\">\"department\"</span>: <span class=\"dd-str\">\"engineering\"</span>},\n      <span class=\"dd-pink\">\"caller\"</span>: {               <span class=\"dd-cmt\">← NEW in 2.0</span>\n        <span class=\"dd-key\">\"type\"</span>: <span class=\"dd-str\">\"code_execution_20260120\"</span>,\n        <span class=\"dd-key\">\"tool_id\"</span>: <span class=\"dd-str\">\"srvtoolu_abc123\"</span>\n      }\n    }\n  ],\n  <span class=\"dd-pink\">\"container\"</span>: {\n    <span class=\"dd-key\">\"id\"</span>: <span class=\"dd-str\">\"container_xyz789\"</span>,\n    <span class=\"dd-key\">\"expires_at\"</span>: <span class=\"dd-str\">\"2026-03-05T14:30:00Z\"</span>\n  }\n}</div>\n      </div>\n      <div>\n        <div class=\"dd-label\">The caller field explained</div>\n        <div class=\"dd-pre\"><span class=\"dd-cmt\">// \"caller\" tells you this tool_use was NOT</span>\n<span class=\"dd-cmt\">// requested by Claude's reasoning directly.</span>\n<span class=\"dd-cmt\">// It was triggered by code running in the</span>\n<span class=\"dd-cmt\">// sandbox container srvtoolu_abc123.</span>\n\n<span class=\"dd-cmt\">// Why this matters for your app:</span>\n<span class=\"dd-cmt\">// 1. You can route tool execution differently</span>\n<span class=\"dd-cmt\">// 2. You know not to render this to the user</span>\n<span class=\"dd-cmt\">// 3. The container is waiting — you MUST</span>\n<span class=\"dd-cmt\">//    respond before expires_at or the</span>\n<span class=\"dd-cmt\">//    sandbox times out</span>\n\n<span class=\"dd-cmt\">// ⚠️  Container TTL: ~4.5 min inactivity</span>\n<span class=\"dd-cmt\">// Always monitor the expires_at field!</span></div>\n        <div style=\"margin-top:10px;\">\n          <div class=\"dd-label\">Container Lifecycle</div>\n          <div class=\"dd-token\">Created:  when first code_execution fires<br/>Reusable: pass container.id in next req<br/>TTL:      ~4.5 min of inactivity<br/>On expiry: Claude may auto-retry call<br/>─────────────────────────────<br/><span class=\"dd-val\">Always check expires_at each response</span></div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- Step 4 -->\n  <div class=\"dd-card\">\n    <div class=\"dd-head\">\n      <div class=\"dd-step-badge\" style=\"color:var(--tool);border-color:var(--tool);background:var(--tool-bg)\">Step 4</div>\n      <div class=\"dd-title\">App runs all tools, returns results — sandbox continues script</div>\n      <div class=\"dd-from\">App → Your Functions → API</div>\n    </div>\n    <div class=\"dd-body dd-cols-3\">\n      <div>\n        <div class=\"dd-label\">App executes get_team_members</div>\n        <div class=\"dd-pre\"><span class=\"dd-cmt\"># Your code</span>\nresult = get_team_members(\n  department=<span class=\"dd-str\">\"engineering\"</span>\n)\n<span class=\"dd-cmt\"># → [{id:1, name:\"Alice\", level:\"L5\"},</span>\n<span class=\"dd-cmt\">#    {id:2, name:\"Bob\",   level:\"L4\"},</span>\n<span class=\"dd-cmt\">#    ... 18 more ...]</span></div>\n      </div>\n      <div>\n        <div class=\"dd-label\">App returns tool_result to API</div>\n        <div class=\"dd-pre\">{\n  <span class=\"dd-key\">\"role\"</span>: <span class=\"dd-str\">\"user\"</span>,\n  <span class=\"dd-key\">\"content\"</span>: [{\n    <span class=\"dd-key\">\"type\"</span>: <span class=\"dd-str\">\"tool_result\"</span>,\n    <span class=\"dd-key\">\"tool_use_id\"</span>: <span class=\"dd-str\">\"toolu_team01\"</span>,\n    <span class=\"dd-key\">\"content\"</span>: <span class=\"dd-str\">\"[{id:1,name:'Alice'...}]\"</span>\n  }],\n  <span class=\"dd-pink\">\"container\"</span>: {\n    <span class=\"dd-key\">\"id\"</span>: <span class=\"dd-str\">\"container_xyz789\"</span>\n  }\n}</div>\n      </div>\n      <div>\n        <div class=\"dd-label\">For parallel get_expenses ×20</div>\n        <div class=\"dd-pre\"><span class=\"dd-cmt\"># Script calls asyncio.gather()</span>\n<span class=\"dd-cmt\"># API pauses sandbox, sends 20</span>\n<span class=\"dd-cmt\"># tool_use blocks simultaneously</span>\n<span class=\"dd-cmt\"># Your app runs all 20 in parallel</span>\n<span class=\"dd-cmt\"># and returns 20 tool_results</span>\n\n<span class=\"dd-cmt\"># 2000+ expense records → processed</span>\n<span class=\"dd-cmt\"># inside the script by Python</span>\n<span class=\"dd-cmt\"># → only overages survive to context</span>\n\n<span class=\"dd-cmt\"># Classic: 22 inferences + 50KB ctx</span>\n<span class=\"dd-cmt\"># Programmatic: 0 extra inferences</span></div>\n      </div>\n    </div>\n  </div>\n\n  <!-- Step 5 -->\n  <div class=\"dd-card\">\n    <div class=\"dd-head\">\n      <div class=\"dd-step-badge\" style=\"color:var(--ctx);border-color:var(--ctx);background:var(--ctx-bg)\">Step 5</div>\n      <div class=\"dd-title\">Script completes → stdout is the only thing Claude sees</div>\n      <div class=\"dd-from\">Sandbox → Claude API → App</div>\n    </div>\n    <div class=\"dd-body dd-cols-2\">\n      <div>\n        <div class=\"dd-label\">server_tool_result (code_execution output)</div>\n        <div class=\"dd-pre\">{\n  <span class=\"dd-key\">\"type\"</span>: <span class=\"dd-str\">\"server_tool_result\"</span>,\n  <span class=\"dd-key\">\"tool_use_id\"</span>: <span class=\"dd-str\">\"srvtoolu_abc123\"</span>,\n  <span class=\"dd-key\">\"content\"</span>: [{\n    <span class=\"dd-key\">\"type\"</span>: <span class=\"dd-str\">\"text\"</span>,\n    <span class=\"dd-key\">\"text\"</span>: <span class=\"dd-str\">\"Over budget: [\n  {'name':'Alice','over':320.50},\n  {'name':'Bob',  'over':148.00},\n  {'name':'Tran', 'over':89.20},\n  {'name':'Diana','over':512.00},\n  {'name':'Kai',  'over':201.75}\n]\"</span>\n  }]\n}</div>\n      </div>\n      <div>\n        <div class=\"dd-label\">Token Summary — Full Lifecycle</div>\n        <div class=\"dd-token\">Step 1 upfront tools:      ~850 tokens<br/>Step 2 user message:        ~20 tokens<br/>Step 2 Claude response:    ~300 tokens<br/>Step 3 tool results (team):~200 tokens<br/>Step 4 expenses (20×):    <span style=\"color:#f472b6\">0 (script)</span><br/>Step 5 script stdout:       ~60 tokens<br/>Step 6 final answer:        ~80 tokens<br/>─────────────────────────────<br/><span class=\"dd-val\">Total: ~1,510 tokens</span><br/><br/>Classic approach:<br/>  22 round-trips + 50KB context<br/>  ~40,000+ tokens<br/><span style=\"color:#f472b6\">Savings: ~96%</span></div>\n      </div>\n    </div>\n  </div>\n\n  <!-- Step 6 -->\n  <div class=\"dd-card\">\n    <div class=\"dd-head\">\n      <div class=\"dd-step-badge\" style=\"color:var(--user);border-color:var(--user);background:var(--user-bg)\">Step 6</div>\n      <div class=\"dd-title\">Claude reads stdout, replies — stop_reason: end_turn</div>\n      <div class=\"dd-from\">Claude API → App → User</div>\n    </div>\n    <div class=\"dd-body dd-cols-2\">\n      <div>\n        <div class=\"dd-label\">Final API Response</div>\n        <div class=\"dd-pre\">{\n  <span class=\"dd-key\">\"stop_reason\"</span>: <span class=\"dd-str\">\"end_turn\"</span>,\n  <span class=\"dd-key\">\"content\"</span>: [{\n    <span class=\"dd-key\">\"type\"</span>: <span class=\"dd-str\">\"text\"</span>,\n    <span class=\"dd-key\">\"text\"</span>: <span class=\"dd-str\">\"5 team members exceeded\ntheir Q3 travel budget:\n\n• Diana  — $512 over limit\n• Alice  — $320 over limit\n• Kai    — $201 over limit\n• Bob    — $148 over limit\n• Tran   — $89 over limit\n\nTotal overage: $1,271.45\"</span>\n  }]\n}</div>\n      </div>\n      <div>\n        <div class=\"dd-label\">Classic vs Programmatic — side by side</div>\n        <div class=\"dd-pre\"><span class=\"dd-cmt\">Classic Calling:</span>\n  API round-trips:   22\n  Inferences:        22\n  Context (peak):    50KB+\n  Token cost:        ~40,000\n  Latency:           ~22 × model_time\n\n<span class=\"dd-cmt\">Programmatic Calling:</span>\n  API round-trips:   2\n  Inferences:        2\n  Context (peak):    ~1.5KB\n  Token cost:        ~1,510\n  Latency:           ~2 × model_time\n                     + tool exec time\n\n<span class=\"dd-cmt\">Real-world wins:</span>\n  Spreadsheet (1000 rows) → Excel plugin\n  Log analysis (10MB file) → filtered\n  Multi-DB aggregation    → summarized</div>\n      </div>\n    </div>\n  </div>\n\n</div><!-- /drilldown panel -->\n\n</div><!-- /page -->\n\n<!-- POPUP -->\n<div class=\"popup\" id=\"popup\">\n  <button class=\"popup-close\" onclick=\"closePopup()\">✕</button>\n  <div class=\"popup-step\" id=\"p-step\"></div>\n  <div class=\"popup-title\" id=\"p-title\"></div>\n  <div class=\"popup-chips\" id=\"p-chips\"></div>\n  <div class=\"popup-desc\" id=\"p-desc\"></div>\n  <div class=\"popup-pre\" id=\"p-code\"></div>\n  <div class=\"popup-token\" id=\"p-token\" style=\"display:none\"></div>\n</div>";

export const script = "\nfunction switchTab(t, el) {\n  document.querySelectorAll('.tab').forEach(e => e.classList.remove('active'));\n  document.querySelectorAll('.panel').forEach(e => e.classList.remove('active'));\n  el.classList.add('active');\n  document.getElementById('panel-' + t).classList.add('active');\n  closePopup();\n}\n\nfunction toggleGrp(el) {\n  el.classList.toggle('closed');\n  el.nextElementSibling.classList.toggle('hidden');\n}\n\nfunction closePopup() {\n  document.getElementById('popup').classList.remove('on');\n}\n\nconst popups = {\n  a1: {\n    step:'A1 — Setup', title:'Register code_execution + tools with allowed_callers',\n    chips:[['App','#fb923c','#1a0e06'],['Claude API','#a78bfa','#120e1e']],\n    desc:'Your app registers three things: the built-in code_execution server tool, and your own tools each flagged with allowed_callers: [\"code_execution\"]. This flag authorizes the sandbox to trigger those tools without requiring a human-in-the-loop round-trip for each one.',\n    code:`\"tools\": [\n  {\"type\": \"code_execution_20260120\", \"name\": \"code_execution\"},\n  {\"name\": \"get_team_members\", \"allowed_callers\": [\"code_execution\"]},\n  {\"name\": \"get_expenses\",     \"allowed_callers\": [\"code_execution\"]},\n  {\"name\": \"get_budget_by_level\", \"allowed_callers\": [\"code_execution\"]}\n]`,\n    token:'~850 tokens upfront. All 3 tools + code_execution in context from the start.'\n  },\n  b1: {\n    step:'B1 — User Message', title:'\"Who exceeded Q3 travel budget?\"',\n    chips:[['User','#38bdf8','#071824'],['App','#fb923c','#1a0e06']],\n    desc:'User asks a natural language question. No special syntax needed — Claude sees the tools available and decides programmatic calling is appropriate for this multi-step data aggregation task.',\n    code:`messages = [\n  {\"role\": \"user\", \"content\": \"Which team members exceeded their Q3 travel budget?\"}\n]`,\n    token:'~20 input tokens for the user message.'\n  },\n  b2: {\n    step:'B2 — API Call', title:'POST /v1/messages with beta header',\n    chips:[['App','#fb923c','#1a0e06'],['Claude API','#a78bfa','#120e1e']],\n    desc:'App sends the request with the advanced-tool-use beta header. First API call of the session.',\n    code:`headers = {\n  \"anthropic-version\": \"2023-06-01\",\n  \"anthropic-beta\": \"advanced-tool-use-2025-11-20\",\n  \"x-api-key\": API_KEY\n}`,\n    token:'First POST /v1/messages. Total input so far: ~870 tokens.'\n  },\n  b3: {\n    step:'B3 — Claude Responds', title:'Claude writes the Python orchestration script',\n    chips:[['Claude API','#a78bfa','#120e1e'],['App','#fb923c','#1a0e06']],\n    desc:'Claude returns stop_reason: \"tool_use\" with a server_tool_use block containing the code_execution input. The input.code field contains the complete Python script Claude wrote — using async/await, asyncio.gather() for parallel calls, and filtering logic. The response also includes a container object with the sandbox ID and expiry.',\n    code:`{\n  \"stop_reason\": \"tool_use\",\n  \"content\": [\n    {\"type\": \"server_tool_use\", \"id\": \"srvtoolu_abc123\",\n     \"name\": \"code_execution\",\n     \"input\": {\"code\": \"team = await get_team_members('engineering')...\"}\n    }\n  ],\n  \"container\": {\"id\": \"container_xyz789\", \"expires_at\": \"...\"}\n}`,\n    token:'Claude output: ~300 tokens (the script). Container spawned on Anthropic infrastructure.'\n  },\n  c1: {\n    step:'C1 — Container Spawn', title:'Sandbox container created',\n    chips:[['Claude API','#a78bfa','#120e1e'],['Code Sandbox','#f472b6','#1a0812']],\n    desc:'When the code_execution tool fires, Anthropic spawns a sandboxed Python environment. The container ID is returned in every subsequent response. You can reuse it by passing the container ID in follow-up requests to maintain script state across turns.',\n    code:`// container object returned in response\n{\n  \"container\": {\n    \"id\": \"container_xyz789\",\n    \"expires_at\": \"2026-03-05T14:30:00Z\"\n  }\n}\n\n// Reuse in next request:\nclient.messages.create(\n  ...,\n  container={\"id\": \"container_xyz789\"}\n)`,\n    token:'Container is free while idle. ~4.5 min TTL. Monitor expires_at on every response.'\n  },\n  c2: {\n    step:'C2 — Script Pauses', title:'Script hits await get_team_members() → sandbox pauses',\n    chips:[['Code Sandbox','#f472b6','#1a0812'],['Your Tools','#fbbf24','#181208']],\n    desc:'When the script reaches an await call for a tool, execution pauses. The API sends your app a tool_use block with a \"caller\" field identifying which sandbox triggered it. Claude is NOT re-invoked — only your app is woken up to execute the function.',\n    code:`// tool_use with caller — new in 2.0\n{\n  \"type\": \"tool_use\",\n  \"id\": \"toolu_team01\",\n  \"name\": \"get_team_members\",\n  \"input\": {\"department\": \"engineering\"},\n  \"caller\": {\n    \"type\": \"code_execution_20260120\",\n    \"tool_id\": \"srvtoolu_abc123\"\n  }\n}`,\n    token:'0 new inference tokens. Only your tool execution code runs — no model involved.'\n  },\n  c3: {\n    step:'C3 — Tool Result', title:'App runs get_team_members, returns tool_result',\n    chips:[['App','#fb923c','#1a0e06'],['Claude API','#a78bfa','#120e1e']],\n    desc:'Your app receives the tool_use, executes the real function, and returns the result as a tool_result. Critically: you must include the container ID so the sandbox knows to resume the paused script.',\n    code:`{\n  \"role\": \"user\",\n  \"content\": [{\n    \"type\": \"tool_result\",\n    \"tool_use_id\": \"toolu_team01\",\n    \"content\": \"[{id:1, name:'Alice', level:'L5'}, ...]\"\n  }],\n  \"container\": {\"id\": \"container_xyz789\"}  // ← required!\n}`,\n    token:'~200 tokens for team list. Script resumes with this data — data goes to sandbox, not to Claude.'\n  },\n  c4: {\n    step:'C4 — Parallel Calls', title:'asyncio.gather() fires 20 parallel get_expenses calls',\n    chips:[['Code Sandbox','#f472b6','#1a0812'],['Your Tools','#fbbf24','#181208']],\n    desc:'Script executes asyncio.gather() with 20 coroutines. The sandbox pauses again and sends your app 20 simultaneous tool_use blocks. You run all 20 in parallel (e.g. asyncio in Python) and return all 20 tool_results in a single response.',\n    code:`// Script code\ntasks = [get_expenses(m[\"id\"], \"Q3\") for m in team]\nall_expenses = await asyncio.gather(*tasks)\n// ↑ Triggers 20 tool_use blocks simultaneously\n\n// Your app runs them in parallel:\nimport asyncio\nresults = await asyncio.gather(*[run_tool(t) for t in tool_uses])`,\n    token:'20 parallel tool calls. No inference. Latency = slowest single call, not sum of 20.'\n  },\n  c5: {\n    step:'C5 — 20 Results Processed', title:'2000+ expense records consumed inside the script',\n    chips:[['App','#fb923c','#1a0e06'],['Code Sandbox','#f472b6','#1a0812']],\n    desc:'App returns 20 tool_results. Each contains 50–100 expense line items. Critically: all 2000+ records are processed by Python logic inside the sandbox script. They never enter Claude\\'s context window. In classic calling, every one of these records would bloat the context.',\n    code:`// In classic calling:\n// 2000+ records → ALL enter Claude's context\n// Claude manually sums each person's expenses\n\n// In programmatic calling:\n// Python script does: sum(e[\"amount\"] for e in expenses)\n// Only the summary survives to context\n// 50KB of raw data → ~60 token summary`,\n    token:'2000+ records processed in Python. Context impact: ~0 tokens. This is the core win.'\n  },\n  c6: {\n    step:'C6 — Budget Lookup', title:'Script fetches budget limits',\n    chips:[['Code Sandbox','#f472b6','#1a0812'],['Your Tools','#fbbf24','#181208']],\n    desc:'Script calls get_budget_by_level() to fetch the budget limits per employee level. Same pattern — sandbox pauses, your app executes the function, returns result, sandbox resumes.',\n    code:`// Script\nbudgets = await get_budget_by_level()\n// → {\"L3\": 2000, \"L4\": 3000, \"L5\": 4000, ...}\n\n// Then immediately:\nfor member, expenses in zip(team, all_expenses):\n    total = sum(e[\"amount\"] for e in expenses)\n    limit = budgets[member[\"level\"]]\n    if total > limit:\n        over.append({\"name\": member[\"name\"], \"over\": total - limit})`,\n    token:'~50 tokens for budget table. Comparison logic runs in Python, never in model.'\n  },\n  c7: {\n    step:'C7 — Script Filters', title:'Script computes overages in Python',\n    chips:[['Code Sandbox','#f472b6','#1a0812']],\n    desc:'All data is now in the sandbox. The script runs the comparison logic entirely in Python — no model inference. The result is a compact list of over-budget members. The script\\'s print() statement is what becomes the stdout captured as the code_execution result.',\n    code:`// Final script output (stdout):\nprint(f\"Over budget: {over}\")\n\n// Output:\n// Over budget: [\n//   {'name': 'Alice', 'over': 320.50},\n//   {'name': 'Bob', 'over': 148.00},\n//   {'name': 'Tran', 'over': 89.20},\n//   {'name': 'Diana', 'over': 512.00},\n//   {'name': 'Kai', 'over': 201.75}\n// ]`,\n    token:'Script produces ~60 tokens of output. This is the ONLY data Claude receives from the whole operation.'\n  },\n  d1: {\n    step:'D1 — Script Output', title:'Sandbox stdout returned as server_tool_result',\n    chips:[['Code Sandbox','#f472b6','#1a0812'],['Claude API','#a78bfa','#120e1e']],\n    desc:'The script\\'s stdout is captured and returned as a server_tool_result for the code_execution tool. Claude now receives this as input to formulate the final answer.',\n    code:`{\n  \"type\": \"server_tool_result\",\n  \"tool_use_id\": \"srvtoolu_abc123\",\n  \"content\": [{\n    \"type\": \"text\",\n    \"text\": \"Over budget: [{'name':'Alice','over':320.50}, ...]\"\n  }]\n}`,\n    token:'~60 tokens into Claude\\'s context. The entire 2000+ expense dataset: 0 tokens.'\n  },\n  e1: {\n    step:'E1 — Final Response', title:'Claude reads stdout → stop_reason: end_turn',\n    chips:[['Claude API','#a78bfa','#120e1e'],['App','#fb923c','#1a0e06']],\n    desc:'Claude receives the script output and formulates a clean, human-readable answer. Second and final API inference call. stop_reason is \"end_turn\".',\n    code:`{\n  \"stop_reason\": \"end_turn\",\n  \"content\": [{\n    \"type\": \"text\",\n    \"text\": \"5 team members exceeded their Q3 travel budget:\n• Diana — $512 over\n• Alice — $320 over\n...\"\n  }]\n}`,\n    token:'Output: ~80 tokens. Total lifecycle: 2 inferences, ~1,510 tokens.'\n  },\n  e2: {\n    step:'E2 — Delivery', title:'App delivers answer to User',\n    chips:[['App','#fb923c','#1a0e06'],['User','#38bdf8','#071824']],\n    desc:'App extracts response.content[0].text and returns it. Full round-trip complete.',\n    code:`final = response.content[0].text\nreturn {\"answer\": final}\n\n# Classic: 22 round-trips, ~22s, 50KB context\n# Programmatic: 2 round-trips, ~2-4s, 1.5KB context`,\n    token:'✅ Done. 2 POST /v1/messages calls. 96% token reduction vs classic approach.'\n  }\n};\n\nfunction showPopup(id) {\n  const d = popups[id];\n  if (!d) return;\n  document.getElementById('p-step').textContent = d.step;\n  document.getElementById('p-title').textContent = d.title;\n  document.getElementById('p-desc').textContent = d.desc;\n  document.getElementById('p-code').textContent = d.code;\n  document.getElementById('p-chips').innerHTML = d.chips.map(([n,c,b]) =>\n    `<span class=\"popup-chip\" style=\"color:${c};border-color:${c};background:${b}\">${n}</span>`\n  ).join('');\n  const tok = document.getElementById('p-token');\n  if (d.token) { tok.style.display='block'; tok.textContent='⚡ '+d.token; }\n  else tok.style.display='none';\n  document.getElementById('popup').classList.add('on');\n}\n\ndocument.addEventListener('click', e => {\n  const popup = document.getElementById('popup');\n  if (popup.classList.contains('on') && !popup.contains(e.target) && !e.target.closest('.msg-row')) {\n    closePopup();\n  }\n});\n";
